import androidx.recyclerview.widget.RecyclerView;
import java.util.List;

public class FeedFragment extends Fragment {
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, ViewGroup container,
                             Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_feed, container, false);

        RecyclerView rvFeed = view.findViewById(R.id.rvFeed);
        if (rvFeed != null && getContext() != null) {
            rvFeed.setLayoutManager(new LinearLayoutManager(getContext()));

            List<FeedEntry> entries = JsonUtils.loadListFromRaw(getContext(), R.raw.mock_feed, FeedEntry.class);
            if (entries != null) {
                rvFeed.setAdapter(new FeedAdapter(entries));
            }
        }

        return view;
    }
}

package com.example.myapplication;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.AdapterView;
import android.widget.ArrayAdapter;
import android.widget.Spinner;
import android.widget.Toast;
import androidx.annotation.NonNull;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import com.google.android.material.button.MaterialButton;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class FeedFragment extends Fragment {
    private FeedAdapter adapter;
    private List<FeedEntry> allEntries;
    private List<FeedEntry> filteredEntries;
    private Spinner spinnerSpeciesFilter;
    private Spinner spinnerStatusFilter;
    private MaterialButton btnResetFilter;
    private String selectedSpecies = "All Species";
    private String selectedStatus = "All Status";
    private List<SaveCategory> categories = new ArrayList<>();

    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, ViewGroup container,
                             Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_feed, container, false);

        RecyclerView rvFeed = view.findViewById(R.id.rvFeed);
        spinnerSpeciesFilter = view.findViewById(R.id.spinnerSpeciesFilter);
        spinnerStatusFilter = view.findViewById(R.id.spinnerStatusFilter);
        btnResetFilter = view.findViewById(R.id.btnResetFilter);

        if (rvFeed != null && getContext() != null) {
            rvFeed.setLayoutManager(new LinearLayoutManager(getContext()));

            allEntries = JsonUtils.loadListFromRaw(getContext(), R.raw.mock_feed, FeedEntry.class);
            if (allEntries != null) {
                // Ensure each entry has proper default values
                for (FeedEntry entry : allEntries) {
                    if (entry.commentCount == 0) entry.commentCount = 0;
                    if (entry.userBadgeLevel == 0) entry.userBadgeLevel = (entry.id % 3); // distribute badges
                }
                
                filteredEntries = new ArrayList<>(allEntries);
                adapter = new FeedAdapter(filteredEntries);
                rvFeed.setAdapter(adapter);

                // Set up save listener
                adapter.setOnSaveClickListener((entry, holder) -> {
                    showSaveDialog(entry, holder);
                });

                // Setup filter spinners
                setupFilterSpinners();

                // Reset filter button
                btnResetFilter.setOnClickListener(v -> {
                    selectedSpecies = "All Species";
                    selectedStatus = "All Status";
                    spinnerSpeciesFilter.setSelection(0);
                    spinnerStatusFilter.setSelection(0);
                    filteredEntries.clear();
                    filteredEntries.addAll(allEntries);
                    adapter.notifyDataSetChanged();
                });
            }
        }

        return view;
    }

    private void setupFilterSpinners() {
        if (getContext() == null || allEntries == null) return;

        // Get unique species from entries
        Set<String> speciesSet = new HashSet<>();
        speciesSet.add("All Species");
        for (FeedEntry entry : allEntries) {
            if (entry.speciesName != null) {
                speciesSet.add(entry.speciesName);
            }
        }
        List<String> speciesList = new ArrayList<>(speciesSet);

        // Get unique statuses
        List<String> statusList = new ArrayList<>();
        statusList.add("All Status");
        statusList.add("LC");
        statusList.add("VU");
        statusList.add("EN");

        // Setup species spinner
        ArrayAdapter<String> speciesAdapter = new ArrayAdapter<>(
                getContext(), android.R.layout.simple_spinner_item, speciesList);
        speciesAdapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
        spinnerSpeciesFilter.setAdapter(speciesAdapter);

        // Setup status spinner
        ArrayAdapter<String> statusAdapter = new ArrayAdapter<>(
                getContext(), android.R.layout.simple_spinner_item, statusList);
        statusAdapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
        spinnerStatusFilter.setAdapter(statusAdapter);

        // Species filter listener
        spinnerSpeciesFilter.setOnItemSelectedListener(new AdapterView.OnItemSelectedListener() {
            @Override
            public void onItemSelected(AdapterView<?> parent, View view, int position, long id) {
                selectedSpecies = (String) parent.getItemAtPosition(position);
                applyFilters();
            }

            @Override
            public void onNothingSelected(AdapterView<?> parent) {}
        });

        // Status filter listener
        spinnerStatusFilter.setOnItemSelectedListener(new AdapterView.OnItemSelectedListener() {
            @Override
            public void onItemSelected(AdapterView<?> parent, View view, int position, long id) {
                selectedStatus = (String) parent.getItemAtPosition(position);
                applyFilters();
            }

            @Override
            public void onNothingSelected(AdapterView<?> parent) {}
        });
    }

    private void applyFilters() {
        filteredEntries.clear();

        for (FeedEntry entry : allEntries) {
            boolean matchesSpecies = selectedSpecies.equals("All Species") || 
                    (entry.speciesName != null && entry.speciesName.equals(selectedSpecies));
            boolean matchesStatus = selectedStatus.equals("All Status") || 
                    (entry.conservationStatus != null && entry.conservationStatus.toUpperCase().equals(selectedStatus));

            if (matchesSpecies && matchesStatus) {
                filteredEntries.add(entry);
            }
        }

        adapter.notifyDataSetChanged();
    }

    private void showSaveDialog(FeedEntry entry, FeedAdapter.FeedViewHolder holder) {
        SaveDialog saveDialog = new SaveDialog(getContext(), entry.id, categories, 
            new SaveDialog.OnSaveListener() {
                @Override
                public void onSave(SaveCategory category) {
                    entry.isSaved = true;
                    Toast.makeText(getContext(), "Saved to \"" + category.name + "\"", Toast.LENGTH_SHORT).show();
                    // Here you would normally save to a database
                    adapter.notifyDataSetChanged();
                }

                @Override
                public void onCreateCategory(String categoryName, String color) {
                    SaveCategory newCategory = new SaveCategory(categoryName, color);
                    categories.add(newCategory);
                    entry.isSaved = true;
                    Toast.makeText(getContext(), "Saved to new category \"" + categoryName + "\"", Toast.LENGTH_SHORT).show();
                    adapter.notifyDataSetChanged();
                }
            });

        saveDialog.show();
    }
}

package com.example.myapplication;

import androidx.room.Entity;
import androidx.room.PrimaryKey;

@Entity(tableName = "save_categories")
public class SaveCategory {
    @PrimaryKey(autoGenerate = true)
    public int id;
    public String name;
    public String color; // hex color code
    public long createdAt;

    public SaveCategory(String name, String color) {
        this.name = name;
        this.color = color;
        this.createdAt = System.currentTimeMillis();
    }

    public SaveCategory() {}
}

package com.example.myapplication;

import android.app.Dialog;
import android.content.Context;
import android.os.Bundle;
import android.view.View;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.Toast;
import androidx.appcompat.app.AlertDialog;
import androidx.core.content.ContextCompat;
import com.google.android.material.button.MaterialButton;
import java.util.List;

public class SaveDialog extends Dialog {
    private Context context;
    private List<SaveCategory> categories;
    private OnSaveListener onSaveListener;
    private int feedEntryId;

    public interface OnSaveListener {
        void onSave(SaveCategory category);
        void onCreateCategory(String categoryName, String color);
    }

    public SaveDialog(Context context, int feedEntryId, List<SaveCategory> categories, OnSaveListener listener) {
        super(context);
        this.context = context;
        this.feedEntryId = feedEntryId;
        this.categories = categories;
        this.onSaveListener = listener;
    }

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.dialog_save_with_categories);

        LinearLayout categoriesContainer = findViewById(R.id.categoriesContainer);
        MaterialButton btnCreateCategory = findViewById(R.id.btnCreateCategory);

        // Display existing categories
        if (categories != null && !categories.isEmpty()) {
            for (SaveCategory category : categories) {
                MaterialButton categoryBtn = new MaterialButton(context);
                categoryBtn.setLayoutParams(new LinearLayout.LayoutParams(
                        LinearLayout.LayoutParams.MATCH_PARENT,
                        LinearLayout.LayoutParams.WRAP_CONTENT
                ));
                categoryBtn.setText(category.name);
                try {
                    categoryBtn.setBackgroundColor(android.graphics.Color.parseColor(category.color));
                } catch (Exception e) {
                    categoryBtn.setBackgroundColor(ContextCompat.getColor(context, R.color.green_light));
                }
                categoryBtn.setTextColor(ContextCompat.getColor(context, R.color.text_primary));
                categoryBtn.setCornerRadius(12);

                LinearLayout.LayoutParams params = (LinearLayout.LayoutParams) categoryBtn.getLayoutParams();
                params.setMargins(0, 8, 0, 8);
                categoryBtn.setLayoutParams(params);

                categoryBtn.setOnClickListener(v -> {
                    if (onSaveListener != null) {
                        onSaveListener.onSave(category);
                    }
                    dismiss();
                });
                categoriesContainer.addView(categoryBtn);
            }
        } else {
            // Show empty state
            View emptyState = new View(context);
            Toast.makeText(context, "No categories yet. Create one!", Toast.LENGTH_SHORT).show();
        }

        btnCreateCategory.setOnClickListener(v -> showCreateCategoryDialog());
    }

    private void showCreateCategoryDialog() {
        AlertDialog.Builder builder = new AlertDialog.Builder(context);
        builder.setTitle("Create New Category");

        LinearLayout layout = new LinearLayout(context);
        layout.setOrientation(LinearLayout.VERTICAL);
        layout.setPadding(50, 40, 50, 40);

        EditText etCategoryName = new EditText(context);
        etCategoryName.setHint("Category name");
        etCategoryName.setTextColor(ContextCompat.getColor(context, R.color.text_primary));
        etCategoryName.setHintTextColor(ContextCompat.getColor(context, R.color.text_hint));
        layout.addView(etCategoryName);

        builder.setView(layout);
        builder.setPositiveButton("Create", (dialog, which) -> {
            String categoryName = etCategoryName.getText().toString().trim();
            if (!categoryName.isEmpty()) {
                if (onSaveListener != null) {
                    // Default color - can expand this later
                    onSaveListener.onCreateCategory(categoryName, "#d4edda");
                }
                dismiss();
            } else {
                Toast.makeText(context, "Please enter a category name", Toast.LENGTH_SHORT).show();
            }
        });
        builder.setNegativeButton("Cancel", null);
        builder.show();
    }
}

package com.example.myapplication;

import androidx.room.Entity;
import androidx.room.ForeignKey;
import androidx.room.PrimaryKey;

@Entity(tableName = "saved_items",
        foreignKeys = @ForeignKey(entity = SaveCategory.class,
                parentColumns = "id",
                childColumns = "categoryId",
                onDelete = ForeignKey.CASCADE))
public class SavedItem {
    @PrimaryKey(autoGenerate = true)
    public int id;
    public int feedEntryId;
    public int categoryId;
    public long savedAt;

    public SavedItem(int feedEntryId, int categoryId) {
        this.feedEntryId = feedEntryId;
        this.categoryId = categoryId;
        this.savedAt = System.currentTimeMillis();
    }

    public SavedItem() {}
}
